const out = [];
const calls = (items[0] && items[0].json && items[0].json.calls) || [];
for (const c of calls) {
  const md = c.metaData || {};
  out.push({
    json: {
      callId: md.id,
      callUrl: md.url,
      title: md.title,
      scheduled: md.scheduled,
      started: md.started,
      durationSec: md.duration,
      language: md.language,
      meetingUrl: md.meetingUrl
    }
  });
}
return out;

// Map Transcript → one item per call with top-level callId
// Prefer callTranscripts[], but fall back to transcripts/transcript/calls/results
const out = [];
const root = (items[0] && items[0].json) || {};

const list = root.callTranscripts
  || root.transcripts
  || root.transcript
  || root.calls
  || root.results
  || [];

for (const entry of list) {
  const callId = entry.callId
    || entry.id
    || (entry.call && entry.call.id)
    || (entry.metaData && entry.metaData.id);

  // Try common transcript segment containers
  const segs = entry.transcript
    || entry.segments
    || entry.sentences
    || entry.utterances
    || entry.items
    || [];

  if (callId) {
    out.push({ json: { callId, transcriptSegments: segs } });
  }
}

return out;

