// Prepare Calls for Agent (one item per call; no {calls:[...]} wrapper)
const MAX_CHARS_PER_CALL = 12000;

function segToText(seg) {
  if (!seg) return '';
  if (typeof seg === 'string') return seg;
  const parts = [];
  if (Array.isArray(seg.sentences)) parts.push(seg.sentences.map(s => (s && s.text) ? String(s.text) : '').join(' '));
  if (seg.text) parts.push(String(seg.text));
  if (seg.utterance) parts.push(String(seg.utterance));
  if (!parts.length) {
    try { parts.push(JSON.stringify(seg)); } catch {}
  }
  return parts.join(' ').trim();
}

// If nothing came in, return [] (downstream nodes won't receive 0 items otherwise)
if (!items || items.length === 0) {
  return [];
}

const calls = items.map(i => {
  const j = i.json || {};
  const segs = Array.isArray(j.transcriptSegments) ? j.transcriptSegments : [];
  const flatText = segs.map(segToText).filter(Boolean).join(' ');
  const trimmed = flatText.slice(0, MAX_CHARS_PER_CALL);
  return {
    callId: String(j.callId ?? ''),
    title: j.title || '',
    callUrl: j.callUrl || '',
    language: j.language || '',
    started: j.started || '',
    durationSec: j.durationSec ?? null,
    quoteable: trimmed,
  };
}).filter(c => c.callId);

// 🔑 Return one item per call (AI Agent will receive all objects)
return calls.map(c => ({ json: c }));

