//--------------------------------------------------------------------
// Input : items = [ { json: { output: "Callid …\nCall title … https://…\n\n…" } }, … ]
// Output: multiple items [{ json: { text } }, …] (plain Slack mrkdwn, no blocks)
//--------------------------------------------------------------------

const MAX_MSG = 39000;      // keep a safety margin under Slack's ~40k char limit
const PER_CALL_LIMIT = 3500; // optional soft cap per call section

function esc(s = '') {
  return String(s).replace(/[&<>]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;'}[c]));
}
function chop(s = '', n = 3500) {
  return s.length > n ? s.slice(0, n - 1) + '…' : s;
}

// Parse one AI Agent "output" blob to a simple text section
function renderCallSection(rawOutput) {
  const raw = String(rawOutput || '').trim();
  if (!raw) return '';

  const lines = raw.split('\n');

  // CallID
  const idLine = lines.find(l => /^Callid\s+/i.test(l));
  const callId = idLine ? idLine.replace(/^Callid\s+/i, '').trim() : '';

  // "Call title <title> <url>"
  const titleLine = lines.find(l => /^Call title\s+/i.test(l));
  let title = '';
  let url = '';
  if (titleLine) {
    const m = titleLine.match(/^Call title\s+(.+?)\s+(https?:\/\/\S+)/i);
    if (m) {
      title = m[1].trim();
      url = m[2].trim();
    } else {
      title = titleLine.replace(/^Call title\s+/i, '').trim();
    }
  }

  const startIdx = titleLine ? lines.indexOf(titleLine) + 1 : 0;
  const body = lines.slice(startIdx).join('\n').trim();

  const titlePart = url
    ? `*<${url}|${esc(title || 'Untitled')}>*`
    : `*${esc(title || 'Untitled')}*`;

  const idPart = callId ? `CallID: \`${esc(callId)}\`` : '';
  const bodyPart = body ? chop(esc(body), PER_CALL_LIMIT) : '';

  // Simple, readable section with a divider line
  const section = [
    titlePart,
    idPart && bodyPart ? `${idPart}\n${bodyPart}` : (idPart || bodyPart),
  ].filter(Boolean).join('\n') + '\n──────────\n';

  return section;
}

// Build all sections
const sections = [];
for (const it of items) {
  const out = it.json?.output ?? '';
  const sec = renderCallSection(out);
  if (sec) sections.push(sec);
}

// Pack into multiple messages under MAX_MSG
const results = [];
let buf = '';

for (const sec of sections) {
  if ((buf + sec).length > MAX_MSG) {
    // flush current message
    if (buf.trim()) results.push({ json: { text: buf.trim() } });
    buf = sec; // start new message
  } else {
    buf += sec;
  }
}
// flush remainder
if (buf.trim()) results.push({ json: { text: buf.trim() } });

// Fallback if nothing parsed
if (!results.length) {
  results.push({ json: { text: 'No content to send.' } });
}

return results;
